import React from 'react';
import styled from 'styled-components';

const SPost = styled.div`
grid-area: 1/1/13/13;
display: grid;
grid-template-columns:repeat(12, 8.333%);  
grid-template-rows:repeat(12, 8.333%); 
background: red ;
color: black ;
font-family: 'TopSecretWoff2' ;
`
const SMessage = styled.div`
grid-area: 1/1/8/13;
background: #33ff33;
`
const STextarea = styled.textarea`
grid-area: 8/1/13/13;
background: #bbff33;
`

const Post = () => {
  return (
<SPost>
<SMessage></SMessage>
<STextarea></STextarea>
</SPost>
  );
};

export default Post ;
